module RefModule (  
    input clk,  
    input reset,  
    input serial_in,  
    output reg [4:0] parallel_out  
);  
    reg [4:0] unused_shift_reg;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            unused_shift_reg <= 5'b0;  
        else  
            unused_shift_reg <= {unused_shift_reg[3:0], serial_in};  
    end  

    always @(*) begin  
        parallel_out = unused_shift_reg;  
    end  
endmodule
